    "code": "<div class=\"flex flex-col gap-4 p-6\" cdkTrapFocus [cdkTrapFocusAutoCapture]=\"true\" zardId=\"alert-dialog\" #z=\"zardId\">\n  @if (config.zTitle || config.zDescription) {\n    <header class=\"flex flex-col gap-2 text-center sm:text-left\">\n      @if (config.zTitle) {\n        <h2 data-testid=\"z-alert-title\" [id]=\"titleId()\" class=\"text-lg font-semibold\">{{ config.zTitle }}</h2>\n      }\n\n      @if (config.zDescription) {\n        <p data-testid=\"z-alert-description\" [id]=\"descriptionId()\" class=\"text-muted-foreground text-sm\">\n          {{ config.zDescription }}\n        </p>\n      }\n    </header>\n  }\n\n  <main>\n    <ng-template cdkPortalOutlet />\n\n    @if (isStringContent()) {\n      <div data-testid=\"z-alert-content\" [innerHTML]=\"config.zContent\"></div>\n    }\n  </main>\n\n  <footer class=\"flex flex-col-reverse gap-2 sm:flex-row sm:justify-end\">\n    @if (config.zCancelText !== null) {\n      <button type=\"button\" data-testid=\"z-alert-cancel-button\" z-button zType=\"outline\" (click)=\"onCancelClick()\">\n        {{ config.zCancelText || 'Cancel' }}\n      </button>\n    }\n\n    @if (config.zOkText !== null) {\n      <button\n        type=\"button\"\n        data-testid=\"z-alert-ok-button\"\n        z-button\n        [zType]=\"config.zOkDestructive ? 'destructive' : 'default'\"\n        [zDisabled]=\"config.zOkDisabled\"\n        (click)=\"onOkClick()\"\n      >\n        {{ config.zOkText || 'Continue' }}\n      </button>\n    }\n  </footer>\n</div>\n",
